package com.i2i.voltwise.web; import org.springframework.http.*; import org.springframework.web.bind.MethodArgumentNotValidException; import org.springframework.web.bind.annotation.*; import java.time.Instant; import java.util.*; @RestControllerAdvice public class ApiExceptionHandler { record ErrorBody(String message,Instant timestamp){} @ExceptionHandler(NoSuchElementException.class) ResponseEntity<ErrorBody> notFound(NoSuchElementException e){return ResponseEntity.status(404).body(new ErrorBody(e.getMessage(),Instant.now()));} @ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<ErrorBody> invalid(MethodArgumentNotValidException e){var m=e.getBindingResult().getFieldErrors().stream().map(x->x.getField()+": "+x.getDefaultMessage()).findFirst().orElse("Geçersiz istek");return ResponseEntity.badRequest().body(new ErrorBody(m,Instant.now()));} @ExceptionHandler(Exception.class) ResponseEntity<ErrorBody> general(Exception e){return ResponseEntity.status(500).body(new ErrorBody("İşlem tamamlanamadı. Lütfen tekrar deneyin.",Instant.now()));} }
